     5→//! Notch and Chalk - Steeplechase commit formatting
     6→//!
     7→//! Provides message formatting for JJ-aware git commits that record session history:
     8→//! - jjx_notch: Standard commit with heat/pace context prefix
     9→//! - jjx_chalk: Empty commit marking a steeplechase event (pace-level)
    10→//! - Heat-level commits: nominate, slate, rail, tally, draft, retire
    11→//!
    12→//! Commit format: `jjb:HALLMARK:IDENTITY:ACTION: message`
    13→//! - HALLMARK: Version identifier (NNNN or NNNN-xxxxxxx)
    14→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
    15→//! - ACTION: Single letter code (required for all commits)
    16→//!
    17→//! The actual commit execution is handled by vorc_commit in the vok crate.
    18→//! This module exports formatting functions that the CLI handlers use.
    19→
    20→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_CORONET_PREFIX as CORONET_PREFIX, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX};
    21→use std::fs;
    22→use std::process::Command;
    23→
    24→/// Commit message prefix
    25→pub const JJRN_COMMIT_PREFIX: &str = "jjb";
    26→
    27→/// Get hallmark for commit message versioning
    28→///
    29→/// Source logic:
    30→/// 1. Try `.vvk/vvbf_brand.json` → if exists, use `vvbh_hallmark` (4 digits)
    31→/// 2. If missing (Kit Forge) → read `Tools/vok/vov_veiled/vovr_registry.json`,
    32→///    find max hallmark, get `git rev-parse --short HEAD`, format as `{hallmark}-{commit}`
    33→fn zjjrn_get_hallmark() -> String {
    34→    // Try reading brand file
    35→    if let Ok(brand_content) = fs::read_to_string(".vvk/vvbf_brand.json") {
    36→        if let Ok(brand_json) = serde_json::from_str::<serde_json::Value>(&brand_content) {
    37→            if let Some(hallmark) = brand_json.get("vvbh_hallmark") {
    38→                if let Some(hallmark_str) = hallmark.as_str() {
    39→                    return hallmark_str.to_string();
    40→                }
    41→            }
    42→        }
    43→    }
    44→
    45→    // Fallback: Kit Forge mode (read registry + git HEAD)
    46→    let mut max_hallmark = 0u32;
    47→    if let Ok(registry_content) = fs::read_to_string("Tools/vok/vov_veiled/vovr_registry.json") {
    48→        if let Ok(registry_json) = serde_json::from_str::<serde_json::Value>(&registry_content) {
    49→            if let Some(hallmarks) = registry_json.get("hallmarks").and_then(|v| v.as_object()) {
    50→                for key in hallmarks.keys() {
    51→                    if let Ok(num) = key.parse::<u32>() {
    52→                        max_hallmark = max_hallmark.max(num);
    53→                    }
    54→                }
    55→            }
    56→        }
    57→    }
    58→
    59→    // Get short commit hash
    60→    let git_output = Command::new("git")
    61→        .args(["rev-parse", "--short", "HEAD"])
    62→        .output();
    63→
    64→    let commit_hash = if let Ok(output) = git_output {
    65→        if output.status.success() {
    66→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    67→        } else {
    68→            "0000000".to_string()
    69→        }
    70→    } else {
    71→        "0000000".to_string()
    72→    };
    73→
    74→    format!("{:04}-{}", max_hallmark, commit_hash)
    75→}
    76→
    77→/// Pace-level chalk markers (single-letter codes)
    78→/// - A = APPROACH: proposed approach before work begins
    79→/// - W = WRAP: pace completion summary
    80→/// - F = FLY: autonomous execution began (bridled pace)
    81→/// - B = BRIDLE: pace transitioned to bridled state
    82→/// - d = discussion: significant decision (lowercase, can be heat-level too)
    83→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    84→pub enum jjrn_ChalkMarker {
    85→    Approach,
    86→    Wrap,
    87→    Fly,
    88→    Bridle,
    89→    Discussion,
    90→}
    91→
    92→impl jjrn_ChalkMarker {
    93→    /// Parse marker from string (accepts both single letter and full word)
    94→    pub fn jjrn_parse(s: &str) -> Result<Self, String> {
    95→        match s {
    96→            "A" | "a" | "APPROACH" | "approach" | "Approach" => Ok(jjrn_ChalkMarker::Approach),
    97→            "W" | "w" | "WRAP" | "wrap" | "Wrap" => Ok(jjrn_ChalkMarker::Wrap),
    98→            "F" | "f" | "FLY" | "fly" | "Fly" => Ok(jjrn_ChalkMarker::Fly),
    99→            "B" | "b" | "BRIDLE" | "bridle" | "Bridle" => Ok(jjrn_ChalkMarker::Bridle),
   100→            "d" | "D" | "DISCUSSION" | "discussion" | "Discussion" => Ok(jjrn_ChalkMarker::Discussion),
   101→            _ => Err(format!(
   102→                "Invalid marker type '{}'. Valid: A(pproach), W(rap), F(ly), B(ridle), d(iscussion)",
   103→                s
   104→            )),
   105→        }
   106→    }
   107→
   108→    /// Get single-letter code for commit message
   109→    pub fn jjrn_code(&self) -> char {
   110→        match self {
   111→            jjrn_ChalkMarker::Approach => 'A',
   112→            jjrn_ChalkMarker::Wrap => 'W',
   113→            jjrn_ChalkMarker::Fly => 'F',
   114→            jjrn_ChalkMarker::Bridle => 'B',
   115→            jjrn_ChalkMarker::Discussion => 'd',
   116→        }
   117→    }
   118→
   119→    /// Get full display string for the marker (for user-facing output)
   120→    pub fn jjrn_as_str(&self) -> &'static str {
   121→        match self {
   122→            jjrn_ChalkMarker::Approach => "APPROACH",
   123→            jjrn_ChalkMarker::Wrap => "WRAP",
   124→            jjrn_ChalkMarker::Fly => "FLY",
   125→            jjrn_ChalkMarker::Bridle => "BRIDLE",
   126→            jjrn_ChalkMarker::Discussion => "discussion",
   127→        }
   128→    }
   129→
   130→    /// Returns true if this marker type requires a pace to be specified
   131→    pub fn jjrn_requires_pace(&self) -> bool {
   132→        match self {
   133→            jjrn_ChalkMarker::Approach | jjrn_ChalkMarker::Wrap | jjrn_ChalkMarker::Fly | jjrn_ChalkMarker::Bridle => true,
   134→            jjrn_ChalkMarker::Discussion => false,
   135→        }
   136→    }
   137→}
   138→
   139→/// Heat-level action codes (single-letter codes)
   140→/// - N = Nominate: create new heat
   141→/// - S = Slate: add new pace
   142→/// - r = rail: reorder paces (lowercase)
   143→/// - T = Tally: add tack to pace
   144→/// - D = Draft: move pace between heats (uppercase, rare)
   145→/// - R = Retire: archive heat (uppercase)
   146→/// - f = furlough: change heat status or rename (lowercase)
   147→/// - G = Garland: celebrate completed heat, create continuation (uppercase)
   148→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
   149→pub enum jjrn_HeatAction {
   150→    Nominate,
   151→    Slate,
   152→    Rail,
   153→    Tally,
   154→    Draft,
   155→    Retire,
   156→    Furlough,
   157→    Garland,
   158→}
   159→
   160→impl jjrn_HeatAction {
   161→    /// Get single-letter code for commit message
   162→    pub fn jjrn_code(&self) -> char {
   163→        match self {
   164→            jjrn_HeatAction::Nominate => 'N',
   165→            jjrn_HeatAction::Slate => 'S',
   166→            jjrn_HeatAction::Rail => 'r',
   167→            jjrn_HeatAction::Tally => 'T',
   168→            jjrn_HeatAction::Draft => 'D',
   169→            jjrn_HeatAction::Retire => 'R',
   170→            jjrn_HeatAction::Furlough => 'f',
   171→            jjrn_HeatAction::Garland => 'G',
   172→        }
   173→    }
   174→
   175→    /// Get full display string (for user-facing output)
   176→    pub fn jjrn_as_str(&self) -> &'static str {
   177→        match self {
   178→            jjrn_HeatAction::Nominate => "nominate",
   179→            jjrn_HeatAction::Slate => "slate",
   180→            jjrn_HeatAction::Rail => "rail",
   181→            jjrn_HeatAction::Tally => "tally",
   182→            jjrn_HeatAction::Draft => "draft",
   183→            jjrn_HeatAction::Retire => "retire",
   184→            jjrn_HeatAction::Furlough => "furlough",
   185→            jjrn_HeatAction::Garland => "garland",
   186→        }
   187→    }
   188→}
   189→
   190→/// Format the notch prefix: jjb:HALLMARK:₢CORONET:n:
   191→///
   192→/// Returns the prefix string to prepend to commit messages for JJ-aware commits.
   193→/// The coronet provides full context (embeds parent firemark).
   194→pub fn jjrn_format_notch_prefix(coronet: &Coronet) -> String {
   195→    let hallmark = zjjrn_get_hallmark();
   196→    format!(
   197→        "{}:{}:{}{}:n: ",
   198→        JJRN_COMMIT_PREFIX,
   199→        hallmark,
   200→        CORONET_PREFIX,
   201→        coronet.jjrf_as_str(),
   202→    )
   203→}
   204→
   205→/// Format the chalk message: jjb:HALLMARK:₢CORONET:X: description
   206→///
   207→/// Returns the full commit message for a chalk (steeplechase marker) commit.
   208→pub fn jjrn_format_chalk_message(coronet: &Coronet, marker: jjrn_ChalkMarker, description: &str) -> String {
   209→    let hallmark = zjjrn_get_hallmark();
   210→    format!(
   211→        "{}:{}:{}{}:{}: {}",
   212→        JJRN_COMMIT_PREFIX,
   213→        hallmark,
   214→        CORONET_PREFIX,
   215→        coronet.jjrf_as_str(),
   216→        marker.jjrn_code(),
   217→        description
   218→    )
   219→}
   220→
   221→/// Format a heat-level discussion message (no pace context): jjb:HALLMARK:₣XX:d: description
   222→pub fn jjrn_format_heat_discussion(firemark: &Firemark, description: &str) -> String {
   223→    let hallmark = zjjrn_get_hallmark();
   224→    format!(
   225→        "{}:{}:{}{}:d: {}",
   226→        JJRN_COMMIT_PREFIX,
   227→        hallmark,
   228→        FIREMARK_PREFIX,
   229→        firemark.jjrf_as_str(),
   230→        description
   231→    )
   232→}
   233→
   234→/// Format a heat-level action message: jjb:HALLMARK:₣XX:X: description
   235→///
   236→/// Used for nominate, slate, rail, tally, draft, retire operations.
   237→pub fn jjrn_format_heat_message(firemark: &Firemark, action: jjrn_HeatAction, description: &str) -> String {
   238→    let hallmark = zjjrn_get_hallmark();
   239→    format!(
   240→        "{}:{}:{}{}:{}: {}",
   241→        JJRN_COMMIT_PREFIX,
   242→        hallmark,
   243→        FIREMARK_PREFIX,
   244→        firemark.jjrf_as_str(),
   245→        action.jjrn_code(),
   246→        description
   247→    )
   248→}
   249→
   250→/// Format a bridle message: jjb:HALLMARK:₢CORONET:B: {agent} | {silks}
   251→///
   252→/// Creates the subject line for a B (bridle) commit.
   253→/// Body should contain the full direction text.
   254→pub fn jjrn_format_bridle_message(coronet: &Coronet, agent: &str, silks: &str) -> String {
   255→    let hallmark = zjjrn_get_hallmark();
   256→    format!(
   257→        "{}:{}:{}{}:B: {} | {}",
   258→        JJRN_COMMIT_PREFIX,
   259→        hallmark,
   260→        CORONET_PREFIX,
   261→        coronet.jjrf_as_str(),
   262→        agent,
   263→        silks
   264→    )
   265→}
