fn zjjrx_run_landing(args: jjrx_LandingArgs) -> i32 {
    use crate::jjrn_notch::jjrn_format_landing_message;

    // Parse coronet
    let coronet = match Coronet::jjrf_parse(&args.coronet) {
        Ok(c) => c,
        Err(e) => {
            eprintln!("jjx_landing: error: {}", e);
            return 1;
        }
    };

    // Read agent output from stdin (the completion report)
    let body = match read_stdin() {
        Ok(b) => b,
        Err(e) => {
            eprintln!("jjx_landing: error reading stdin: {}", e);
            return 1;
        }
    };

    // Build landing commit message
    let subject = jjrn_format_landing_message(&coronet, &args.agent);
    let message = format!("{}\n\n{}", subject, body);

    // Create empty commit with the landing message
    let commit_args = vvc::vvcc_CommitArgs {
        prefix: None,
        message: Some(message),
        allow_empty: true,
        no_stage: true,
        size_limit: vvc::VVCG_SIZE_LIMIT,
        warn_limit: vvc::VVCG_WARN_LIMIT,
    };

    vvc::commit(&commit_args)
}

